class PaymentValidator {
    fun validate(request: PaymentRequest) {
        require(request.amount > BigDecimal.ZERO) { "Amount must be greater than zero" }
        require(request.currency.isNotBlank()) { "Currency is required" }
        require(request.userId.isNotBlank()) { "User ID is required" }
        when (request.paymentType) {
            PaymentType.IN_APP_PURCHASE -> require(!request.productId.isNullOrBlank()) { "Product ID is required" }
            PaymentType.WALLET_TOP_UP -> require(!request.sourceToken.isNullOrBlank()) { "Source token is required" }
            PaymentType.WALLET_TRANSFER -> {
                require(!request.destinationUserId.isNullOrBlank()) { "Destination user ID is required" }
                require(request.destinationUserId != request.userId) { "Cannot transfer to self" }
            }
        }
    }
}

