class PaymentAuditLogger {
    fun logStart(request: PaymentRequest) {}
    fun logSuccess(result: PaymentResult) {}
    fun logFailure(transactionId: String, reason: String) {}
}

class PaymentProcessor(
    private val context: Context,
    private val gateway: PaymentGateway,
    private val purchaseProvider: InAppPurchaseProvider,
    private val walletDataSource: WalletDataSource,
    private val validator: PaymentValidator = PaymentValidator(),
    private val crypto: SecurePaymentCrypto = SecurePaymentCrypto(),
    private val auditLogger: PaymentAuditLogger = PaymentAuditLogger()
) {
    suspend fun process(activity: Activity?, request: PaymentRequest): PaymentResult {
        validator.validate(request)
        auditLogger.logStart(request)

        return try {
            when (request.paymentType) {
                PaymentType.IN_APP_PURCHASE -> handleInAppPurchase(activity, request)
                PaymentType.WALLET_TOP_UP -> handleWalletTopUp(request)
                PaymentType.WALLET_TRANSFER -> handleWalletTransfer(request)
            }.also {
                walletDataSource.saveTransaction(it)
                if (it.status == PaymentStatus.SUCCESS) {
                    auditLogger.logSuccess(it)
                } else {
                    auditLogger.logFailure(it.transactionId, it.message)
                }
            }
        } catch (e: Exception) {
            val failed = PaymentResult(
                transactionId = UUID.randomUUID().toString(),
                status = PaymentStatus.FAILED,
                message = e.message ?: "Payment processing failed"
            )
            walletDataSource.saveTransaction(failed)
            auditLogger.logFailure(failed.transactionId, failed.message)
            failed
        }
    }

    private suspend fun handleInAppPurchase(activity: Activity?, request: PaymentRequest): PaymentResult {
        require(activity != null) { "Activity is required for in-app purchase flow" }
        val purchaseResult = purchaseProvider.launchPurchase(activity, request.productId!!)
        if (purchaseResult.status != PaymentStatus.SUCCESS || purchaseResult.receipt.isNullOrBlank()) {
            return purchaseResult
        }

        val verified = gateway.verifyReceipt(purchaseResult.receipt)
        if (!verified) {
            return purchaseResult.copy(
                status = PaymentStatus.FAILED,
                message = "Receipt verification failed"
            )
        }

        val acknowledged = purchaseProvider.acknowledgePurchase(purchaseResult.receipt)
        return if (acknowledged) {
            purchaseResult.copy(message = "Purchase completed and acknowledged")
        } else {
            purchaseResult.copy(status = PaymentStatus.FAILED, message = "Purchase acknowledgement failed")
        }
    }

    private suspend fun handleWalletTopUp(request: PaymentRequest): PaymentResult {
        val payload = buildSensitivePayload(request)
        val encrypted = crypto.encrypt(payload)
        val chargeResult = gateway.charge(encrypted)

        if (chargeResult.status == PaymentStatus.SUCCESS) {
            val credited = walletDataSource.credit(request.userId, request.amount)
            if (!credited) {
                return chargeResult.copy(status = PaymentStatus.FAILED, message = "Wallet credit failed")
            }
        }

        return chargeResult
    }

    private suspend fun handleWalletTransfer(request: PaymentRequest): PaymentResult {
        val debited = walletDataSource.debit(request.userId, request.amount)
        if (!debited) {
            return PaymentResult(
                transactionId = UUID.randomUUID().toString(),
                status = PaymentStatus.FAILED,
                message = "Insufficient balance or debit failed"
            )
        }

        val credited = walletDataSource.credit(request.destinationUserId!!, request.amount)
        return if (credited) {
            PaymentResult(
                transactionId = UUID.randomUUID().toString(),
                status = PaymentStatus.SUCCESS,
                message = "Wallet transfer completed"
            )
        } else {
            walletDataSource.credit(request.userId, request.amount)
            PaymentResult(
                transactionId = UUID.randomUUID().toString(),
                status = PaymentStatus.FAILED,
                message = "Destination wallet credit failed, funds reversed"
            )
        }
    }

    private fun buildSensitivePayload(request: PaymentRequest): String {
        return listOf(
            "userId=${request.userId}",
            "amount=${request.amount}",
            "currency=${request.currency}",
            "paymentType=${request.paymentType}",
            "sourceToken=${request.sourceToken.orEmpty()}",
            "productId=${request.productId.orEmpty()}",
            "idempotencyKey=${request.idempotencyKey}"
        ).joinToString("&")
    }
}